10		// Track which sessions are expanded
11		let expanded = $state<Set<string>>(new Set());
12		let sessionBodies = $state<Record<string, Pick<SessionNode, 'prompt' | 'response' | 'stderr'>>>(
13			{}
14		);
15		let sessionExecutions = $state<Record<string, string | null>>({});
16	
17		function executionHref(executionId: string): string {
18			return `/nodes/${data.nodeId}/projects/${data.projectId}/executions/${executionId}`;
19		}
20	
21		onMount(() => {
22			const timer = window.setInterval(() => {
23				void invalidateAll();
24			}, 2000);
25			return () => window.clearInterval(timer);
26		});
27	
28		async function toggle(id: string) {
29			const next = new Set(expanded);
30			if (next.has(id)) {
31				next.delete(id);
32			} else {
33				next.add(id);
34				if (!sessionBodies[id]) {
35					const client = createClient(fetch);
36					const detail = await client.request<{ agentSession: SessionNode | null }>(
37						SESSION_DETAIL_QUERY,
38						{ id }
39					);
40					if (detail.agentSession) {
41						sessionBodies = {
42							...sessionBodies,
43							[id]: {
44								prompt: detail.agentSession.prompt,
45								response: detail.agentSession.response,
46								stderr: detail.agentSession.stderr
47							}
48						};
49					}
50				}
51				if (sessionExecutions[id] === undefined) {
52					try {
53						const client2 = createClient(fetch);
54						const exec = await client2.request<{ executionBySessionId: { id: string } | null }>(
55							SESSION_EXECUTION_QUERY,
56							{ projectID: data.projectId, sessionID: id }
57						);
58						sessionExecutions = {
59							...sessionExecutions,
60							[id]: exec.executionBySessionId?.id ?? null
61						};
62					} catch {
63						sessionExecutions = { ...sessionExecutions, [id]: null };
64					}
65				}
66			}
67			expanded = next;
68		}
