70		const recordingGap = $derived.by(() => {
71			const sorted = [...data.sessions.edges].sort(
72				(a, b) => new Date(a.node.startedAt).getTime() - new Date(b.node.startedAt).getTime()
73			);
74			for (let i = 1; i < sorted.length; i++) {
75				const prev = new Date(sorted[i - 1].node.startedAt);
76				const next = new Date(sorted[i].node.startedAt);
77				if (next.getTime() - prev.getTime() > 24 * 60 * 60 * 1000) {
78					return `No sessions recorded between ${prev.toLocaleDateString()} and ${next.toLocaleDateString()}`;
79				}
80			}
81			return null;
82		});
83	
84		// Aggregate token summary
85		const summary = $derived.by(() => {
86			let totalPrompt = 0;
87			let totalCompletion = 0;
88			let totalCached = 0;
89			let totalTokens = 0;
90			let paidSessions = 0;
91			let subscriptionSessions = 0;
92			for (const edge of data.sessions.edges) {
93				const s = edge.node;
94				if (s.billingMode === 'paid') paidSessions++;
95				if (s.billingMode === 'subscription') subscriptionSessions++;
96				if (s.tokens) {
97					totalPrompt += s.tokens.prompt ?? 0;
98					totalCompletion += s.tokens.completion ?? 0;
99					totalCached += s.tokens.cached ?? 0;
100					totalTokens += s.tokens.total ?? 0;
101				}
102			}
103			const cacheRate = totalTokens > 0 ? Math.round((totalCached / totalTokens) * 100) : 0;
104			return {
105				totalPrompt,
106				totalCompletion,
107				totalCached,
108				totalTokens,
109				cacheRate,
110				paidSessions,
111				subscriptionSessions
112			};
113		});
